import React from 'react';
import { ComposableMap, Geographies, Geography, Marker, Line } from "react-simple-maps";

const geoUrl = "https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json";

const AttackMap = ({ history }) => {
  // Coordinates mapping
  const locations = {
    'Russia': [100, 60],
    'China': [104, 35],
    'USA': [-95, 38],
    'Brazil': [-50, -10],
    'India': [78, 20] 
  };

  const targetCoords = locations['India'];

  // Filter history to ONLY show actual attacks, so they stay on the screen!
  const activeAttacks = history ? history.filter(threat => threat.attack_type !== 'Normal') : [];

  return (
    <div style={{ width: '100%', height: '100%', display: 'flex', justifyContent: 'center', alignItems: 'center', background: '#baddf9', borderRadius: '8px' }}>
      <ComposableMap projectionConfig={{ scale: 140 }} style={{ width: "100%", height: "100%" }}>
        <Geographies geography={geoUrl}>
          {({ geographies }) =>
            geographies.map((geo) => (
              <Geography 
                key={geo.rsmKey} 
                geography={geo} 
                fill="#fdfbf1"      /* Light tan/white continents */
                stroke="#c0c4c8"    /* Light gray borders */
                strokeWidth={0.5} 
                style={{
                  default: { outline: "none" },
                  hover: { fill: "#f0eedc", outline: "none" },
                  pressed: { outline: "none" }
                }}
              />
            ))
          }
        </Geographies>

        {/* Draw ALL recent attacks with their IP addresses */}
        {activeAttacks.map((threat, index) => {
          const originCoords = locations[threat.origin_country] || locations['Russia'];
          
          return (
            <g key={index}>
              <Line
                from={originCoords}
                to={targetCoords}
                stroke="#ef4444"
                strokeWidth={2}
                strokeLinecap="round"
                style={{ strokeDasharray: "4 4" }}
              />
              <Marker coordinates={originCoords}>
                <circle r={5} fill="#ef4444" />
                {/* This prints the IP address visibly on the map! */}
                <text textAnchor="middle" y={-10} style={{ fontFamily: "monospace", fill: "#b91c1c", fontSize: "12px", fontWeight: "bold", textShadow: "1px 1px 2px white" }}>
                  {threat.source_ip}
                </text>
              </Marker>
            </g>
          );
        })}

        {/* Target Node (India) */}
        <Marker coordinates={targetCoords}>
          <circle r={6} fill="#2563eb" />
          <circle r={12} fill="transparent" stroke="#2563eb" strokeWidth={2} />
          <text textAnchor="middle" y={22} style={{ fontFamily: "Arial", fill: "#1e3a8a", fontSize: "12px", fontWeight: "bold" }}>
            SOC NODE
          </text>
        </Marker>
      </ComposableMap>
    </div>
  );
};

export default AttackMap;
